#include <bits/stdc++.h>
using namespace std;

int n, tmp, cnt1, cnt2;
vector<int> l[200005];
int vis[200005];

void DFS(int root, bool clr) {
    vis[root] = clr + 1;
    if (!clr) cnt1++;
    if (clr) cnt2++;
    for (int i : l[root]) {
        if (!vis[i]) {
            DFS(i, !clr);
        }
    }
}

int main() {
    cin >> n;
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        cin >> u >> v;
        l[u].push_back(v);
        l[v].push_back(u);
    }
    DFS(1, 0);
    for (int i = 1; i <= n; i++) {
        cout << (vis[i] == 1 ? cnt1 : cnt2) << ' ';
    }
    return 0;
}
